SELECT p.principal_id AS "principalId", p.tenant_id AS "tenantId", p.principal_type AS "principalType", p.principal_status AS "principalStatus", p.aggregate_version AS "aggregateVersion", p.created_at AS "createdAt", p.updated_at AS "updatedAt", p.disabled_at AS "disabledAt", p.disabled_by AS "disabledBy", p.disabled_reason AS "disabledReason", profile.display_name AS "displayName", profile.employee_number AS "employeeNumber", profile.profile_version AS "profileVersion" FROM idn_security_principal p JOIN idn_person_profile profile ON profile.tenant_id=p.tenant_id AND profile.principal_id=p.principal_id WHERE p.tenant_id=#{tenantId} AND p.principal_status=#{status}
AND (lower(profile.display_name) LIKE lower(#{query}) || '%' OR profile.employee_number=#{query})
AND (lower(profile.display_name), p.principal_id) > (lower(#{cursorName}), #{cursorId})
ORDER BY lower(profile.display_name), p.principal_id LIMIT #{fetchSize}
